from .. import ICoveragePyEbyeAggregatorfrom ..._private.e_cov_reporttype import ECoverageReportTypefrom .._private.json_covebyeaggr import JsonCoverageEbyeAggregatorclass CoveragePyEbyeAggregatorFactory:	"""		Represents a factory for each `ICoveragePyEbyeAggregator`	"""			@classmethod	def create(			cls,			report_type: ECoverageReportType,	) -> ICoveragePyEbyeAggregator:		"""			Instantiates a new entity-by-entity coverage data aggregator, derived from coverage.py,            that supports the specified report type                        Parameters            ----------				report_type: ECoverageReportType                    An `ECoverageReportType` value representing the coverage.py report type                    supported by the requested `ICoveragePyEbyeAggregator` object                                Returns            -------				ICoveragePyEbyeAggregator                    An `ICoveragePyEbyeAggregator` object representing the entity-by-entity                    aggregator of coverage data from coverage.py that supports the requested                    report type								Raises            ------                NotImplementedError                    Occurs if a `report_type` is provided for which no                    `ICoveragePyEbyeAggregator` is implemented		"""		obj: ICoveragePyEbyeAggregator				match report_type:			case ECoverageReportType.JSON:				obj = JsonCoverageEbyeAggregator()					return obj